UPDATE LINE_LIMIT
SET is_daily_limit_active = #{isActive}, updated_at = now()
WHERE limit_id = #{limitId} AND deleted_at IS NULL;

UPDATE LINE_LIMIT
SET is_shared_limit_active = #{isActive}, updated_at = now()
WHERE limit_id = #{limitId} AND deleted_at IS NULL;

UPDATE LINE_LIMIT
SET daily_data_limit = #{policyValue}, updated_at = now()
WHERE limit_id = #{limitPolicyId} AND deleted_at IS NULL;

UPDATE LINE_LIMIT
SET shared_data_limit = #{policyValue}, updated_at = now()
WHERE limit_id = #{limitPolicyId} AND deleted_at IS NULL;
